namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly List<Notification> _notifications = [];

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature available: Dark Mode.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>
    /// Returns all notifications currently available.
    /// </summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>
    /// Returns only notifications newer than the given timestamp.
    /// </summary>
    public List<Notification> GetSince(DateTime since)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Timestamp > since).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally or by a background process.
    /// </summary>
    public void SimulateNewNotification()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Server maintenance scheduled.",
            "Your export is ready to download.",
            "Reminder: meeting in 15 minutes.",
            "New comment on your article."
        };

        lock (_lock)
        {
            var message = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new Notification(_nextId++, message, DateTime.UtcNow));
        }
    }
}

