@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in _notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <strong>#@notification.Id</strong> &mdash; @notification.Message
                </div>
                <small class="text-muted">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = [];
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // Load initial data during prerender AND on interactive init.
        // This ensures SSR HTML is populated immediately.
        _notifications = NotificationService.GetAll();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is live in the browser,
            // never during static SSR prerendering. Start polling here.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
